(() => {
    const components = window.SUXI_ONLINE_DATA_COMPONENTS || {};

    components.CtripProfileFieldConfigPanelBody = {
        name: 'CtripProfileFieldConfigPanelBody',
        props: {
            ctx: {
                type: Object,
                required: true,
            },
        },
        setup(props) {
            return new Proxy({}, {
                get(target, key) {
                    if (key === 'ctx') return props.ctx;
                    return props.ctx?.[key] ?? target[key];
                },
                set(target, key, value) {
                    if (props.ctx) {
                        props.ctx[key] = value;
                        return true;
                    }
                    target[key] = value;
                    return true;
                },
                has(target, key) {
                    return key in target || !!props.ctx;
                },
                ownKeys(target) {
                    return Reflect.ownKeys(target);
                },
                getOwnPropertyDescriptor() {
                    return {
                        enumerable: true,
                        configurable: true,
                    };
                },
            });
        },
        template: "<div v-if=\"onlineDataTab === 'profile-fields' && user?.is_super_admin\" data-testid=\"ctrip-profile-field-config-panel\" class=\"space-y-4\">\n                                    <div class=\"border rounded-lg bg-white overflow-hidden\">\n                                        <div class=\"p-4 border-b flex flex-col lg:flex-row lg:items-center lg:justify-between gap-3\">\n                                            <div>\n                                                <h4 class=\"text-lg font-semibold text-gray-900\">携程登录会话字段配置</h4>\n                                                <div class=\"text-xs text-gray-500 mt-1\">\n                                                    配置 {{ ctripProfileFieldSummary.total || ctripProfileFields.length }} 个字段，已确认 {{ ctripProfileConfirmedFieldCount }} 个，存疑待修正 {{ ctripProfileDoubtfulFieldCount }} 个；抓取结果 {{ ctripProfileCaptureResultText }}；历史有值 {{ ctripProfileFieldSampleLoading ? '加载中' : (ctripProfileFieldSamplesLoaded ? ctripProfileFieldSampledCount + ' 个字段' : '未加载') }}；人工核验 相符 {{ ctripProfileFieldSummary.sample_verification_counts?.matched || 0 }} / 不符 {{ ctripProfileFieldSummary.sample_verification_counts?.mismatched || 0 }} / 待核验 {{ ctripProfileFieldSummary.sample_verification_counts?.unverified || 0 }}；自动获取关键字段 {{ ctripProfileFieldSummary.auto_fetch_field_count || 0 }} 个，待同步 {{ ctripProfileFieldSummary.auto_fetch_missing_field_count || 0 }} 个，已跳过非关键字段 {{ ctripProfileFieldSummary.auto_fetch_skipped_field_count || 0 }} 个\n                                                </div>\n                                            </div>\n                                            <div class=\"flex flex-wrap gap-2\">\n                                                <button type=\"button\" @click=\"openCtripProfileModuleManager\"\n                                                    class=\"px-3 py-2 text-sm border rounded-lg hover:bg-gray-50\">\n                                                    <i class=\"fas fa-sliders-h mr-1\"></i>模块管理\n                                                </button>\n                                                <button type=\"button\" @click=\"applyCtripProfileFieldSections\" :disabled=\"ctripProfileFieldLoading\"\n                                                    class=\"px-3 py-2 text-sm border rounded-lg hover:bg-gray-50 disabled:text-gray-400\">\n                                                    <i class=\"fas fa-layer-group mr-1\"></i>同步默认字段\n                                                </button>\n                                                <button type=\"button\" @click=\"recheckCtripProfileMismatchedFields\"\n                                                    :disabled=\"ctripProfileFieldRechecking || ctripProfileFieldLoading || ctripProfileFieldSampleLoading || !ctripProfileFieldSamplesLoaded || ctripBrowserCaptureRunning || !ctripProfileFieldRecheckTargetCount\"\n                                                    class=\"px-3 py-2 text-sm border rounded-lg hover:bg-gray-50 disabled:text-gray-400\">\n                                                    <i :class=\"ctripProfileFieldRechecking ? 'fas fa-spinner fa-spin mr-1' : 'fas fa-sync-alt mr-1'\"></i>{{ ctripProfileFieldRechecking ? '重抓中...' : '重抓缺口/不符' }}\n                                                </button>\n                                                <button type=\"button\" @click=\"openCtripProfileFieldCreateForm\"\n                                                    class=\"px-3 py-2 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700\">\n                                                    <i class=\"fas fa-plus mr-1\"></i>新增字段配置\n                                                </button>\n                                            </div>\n                                        </div>\n\n                                        <div data-testid=\"ctrip-profile-field-asset-ledger\" class=\"p-4 border-b bg-slate-50\">\n                                            <div class=\"grid grid-cols-2 lg:grid-cols-4 gap-3\">\n                                                <div v-for=\"card in ctripProfileFieldAssetLedgerCards\" :key=\"card.key\" class=\"rounded-lg border border-slate-200 bg-white p-3\">\n                                                    <div class=\"flex items-center justify-between gap-2\">\n                                                        <div class=\"text-xs text-slate-500\">{{ card.label }}</div>\n                                                        <span :class=\"['rounded-full px-2 py-0.5 text-[11px]', card.className]\">{{ card.badge }}</span>\n                                                    </div>\n                                                    <div class=\"mt-1 text-lg font-semibold text-slate-900\">{{ card.value }}</div>\n                                                    <div class=\"mt-1 min-h-[2rem] text-xs leading-4 text-slate-500\" :title=\"card.detail\">{{ card.detail }}</div>\n                                                </div>\n                                            </div>\n                                            <div class=\"mt-3 rounded-md border border-red-100 bg-red-50 px-3 py-2 text-xs leading-5 text-red-700\">\n                                                禁止采集：{{ ctripProfileForbiddenFieldAssets.map(item => item.label).join(' / ') }}。这些字段不进入标准字段表，不用空值或脱敏值伪装成已采集。\n                                            </div>\n                                        </div>\n\n                                        <div v-if=\"ctripProfileFieldRecheckState.active || ctripProfileFieldRecheckState.message\" class=\"p-4 border-b bg-blue-50/60\">\n                                            <div class=\"flex flex-col lg:flex-row lg:items-start lg:justify-between gap-3\">\n                                                <div class=\"min-w-0\">\n                                                    <div class=\"flex flex-wrap items-center gap-2\">\n                                                        <span :class=\"['inline-flex items-center rounded-md border px-2 py-0.5 text-xs font-medium', ctripProfileFieldRecheckState.type === 'error' ? 'border-red-200 bg-red-50 text-red-700' : (ctripProfileFieldRecheckState.type === 'success' ? 'border-emerald-200 bg-emerald-50 text-emerald-700' : (ctripProfileFieldRecheckState.type === 'warning' ? 'border-amber-200 bg-amber-50 text-amber-700' : 'border-blue-200 bg-white text-blue-700'))]\">\n                                                            <i :class=\"ctripProfileFieldRecheckState.active ? 'fas fa-spinner fa-spin mr-1' : (ctripProfileFieldRecheckState.type === 'error' ? 'fas fa-exclamation-circle mr-1' : 'fas fa-check-circle mr-1')\"></i>\n                                                            {{ ctripProfileFieldRecheckProgress.stageText }}\n                                                        </span>\n                                                        <span class=\"text-xs text-slate-500\">预计 {{ ctripProfileFieldRecheckEstimatedText }}；超过 5 分钟请检查登录会话或浏览器占用。</span>\n                                                    </div>\n                                                    <div class=\"mt-2 text-sm text-slate-800\">{{ ctripProfileFieldRecheckState.message }}</div>\n                                                    <div v-if=\"ctripProfileFieldRecheckSectionText\" class=\"mt-1 text-xs text-slate-500\">重抓模块：{{ ctripProfileFieldRecheckSectionText }}</div>\n                                                </div>\n                                                <div class=\"shrink-0 text-right\">\n                                                    <div class=\"text-lg font-semibold text-blue-700\">{{ ctripProfileFieldRecheckProgress.percent }}%</div>\n                                                    <div class=\"text-xs text-slate-500\">已耗时 {{ formatAutoFetchElapsed(autoFetchRunElapsedSeconds) }}</div>\n                                                </div>\n                                            </div>\n                                            <div class=\"mt-3 h-2 rounded-full bg-white border border-blue-100 overflow-hidden\">\n                                                <div :class=\"['h-full rounded-full transition-all', ctripProfileFieldRecheckState.type === 'error' ? 'bg-red-500' : (ctripProfileFieldRecheckState.type === 'success' ? 'bg-emerald-500' : (ctripProfileFieldRecheckState.type === 'warning' ? 'bg-amber-500' : 'bg-blue-600'))]\" :style=\"{ width: ctripProfileFieldRecheckProgress.percent + '%' }\"></div>\n                                            </div>\n                                            <div class=\"mt-2 text-xs text-slate-500\">百分比为前端按阶段估算，真实结束以“完成/失败”提示和获取值刷新结果为准。</div>\n                                        </div>\n\n                                        <div class=\"p-4 border-b bg-gray-50 grid grid-cols-1 md:grid-cols-6 gap-3\">\n                                            <input v-model.trim=\"ctripProfileFieldFilters.keyword\" type=\"text\"\n                                                class=\"md:col-span-2 px-3 py-2 border rounded-lg text-sm\"\n                                                placeholder=\"搜索字段、接口、JSON路径、入库字段、获取值\">\n                                            <select v-model=\"ctripProfileFieldFilters.section\" class=\"px-3 py-2 border rounded-lg text-sm\">\n                                                <option value=\"\">全部模块</option>\n                                                <option v-for=\"option in ctripProfileFieldSectionOptions\" :key=\"option.value\" :value=\"option.value\">{{ option.label }}</option>\n                                            </select>\n                                            <select v-model=\"ctripProfileFieldFilters.status\" class=\"px-3 py-2 border rounded-lg text-sm\">\n                                                <option value=\"\">全部状态</option>\n                                                <option value=\"confirmed\">已确认</option>\n                                                <option value=\"needs_section\">存疑待修正：需采集范围</option>\n                                                <option value=\"needs_parser\">存疑待修正：待补解析</option>\n                                                <option value=\"not_captured\">存疑待修正：未采集</option>\n                                                <option value=\"pending\">存疑待修正：待确认</option>\n                                                <option value=\"paused\">存疑待修正：停用</option>\n                                            </select>\n                                            <select v-model=\"ctripProfileFieldFilters.enabled\" class=\"px-3 py-2 border rounded-lg text-sm\">\n                                                <option value=\"\">全部启用</option>\n                                                <option value=\"enabled\">启用</option>\n                                                <option value=\"disabled\">停用</option>\n                                            </select>\n                                            <div class=\"flex items-center gap-2\">\n                                                <select v-model=\"ctripProfileFieldFilters.sample\" class=\"w-full px-3 py-2 border rounded-lg text-sm\">\n                                                    <option value=\"\">全部获取值</option>\n                                                    <option value=\"with_sample\">有获取值</option>\n                                                    <option value=\"not_returned\">未返回获取值</option>\n                                                    <option value=\"without_sample\">无获取值</option>\n                                                </select>\n                                                <button type=\"button\" @click=\"resetCtripProfileFieldFilters\" class=\"px-3 py-2 border rounded-lg text-sm hover:bg-white whitespace-nowrap\">清空</button>\n                                            </div>\n                                                <div class=\"md:col-span-6 text-xs text-gray-500\">\n                                                筛选 {{ filteredCtripProfileFields.length }} / {{ ctripProfileFields.length }} 个字段<span v-if=\"ctripProfileFieldSampleLoading\">；获取值加载中...</span><span v-else-if=\"!ctripProfileFieldSamplesLoaded\">；获取值未加载</span>\n                                            </div>\n                                        </div>\n\n                                        <teleport to=\"body\">\n                                        <div v-if=\"showCtripProfileModuleManager\"\n                                            class=\"fixed inset-0 bg-slate-900/45 px-4 py-6 overflow-y-auto\"\n                                            style=\"z-index: 78;\"\n                                            data-testid=\"ctrip-profile-module-manager\">\n                                            <div class=\"flex min-h-full items-center justify-center\" @click.self=\"closeCtripProfileModuleManager\">\n                                            <div class=\"flex w-full max-w-6xl max-h-[calc(100vh-72px)] flex-col rounded-lg bg-white shadow-2xl\">\n                                                <div class=\"flex items-start justify-between gap-3 border-b px-4 py-3\">\n                                                    <div>\n                                                        <div class=\"text-base font-semibold text-gray-900\">模块管理</div>\n                                                        <div class=\"mt-1 text-xs text-gray-500\">字段配置下拉、自动采集字段范围和删除停用规则统一读取这里的模块配置。</div>\n                                                    </div>\n                                                    <button type=\"button\" @click=\"closeCtripProfileModuleManager\"\n                                                        class=\"h-8 w-8 shrink-0 rounded-lg border text-gray-500 hover:bg-gray-50\"\n                                                        title=\"关闭\">\n                                                        <i class=\"fas fa-times\"></i>\n                                                    </button>\n                                                </div>\n                                                <div class=\"min-h-0 flex-1 overflow-y-auto p-4\">\n                                                    <div class=\"mb-4\">\n                                                        <div class=\"mb-2 flex items-center justify-between gap-2\">\n                                                            <div class=\"text-xs font-medium text-gray-500\">一级指标</div>\n                                                            <button v-if=\"ctripProfileModuleCategoryFilter\" type=\"button\" @click=\"ctripProfileModuleCategoryFilter = ''\" class=\"text-xs text-blue-600 hover:text-blue-700\">查看全部模块</button>\n                                                        </div>\n                                                        <div class=\"grid grid-cols-1 gap-2 sm:grid-cols-2 xl:grid-cols-4\">\n                                                            <button v-for=\"category in ctripProfilePrimaryCategoryCards\" :key=\"category.name\" type=\"button\"\n                                                                @click=\"ctripProfileModuleCategoryFilter = category.name\"\n                                                                :class=\"['rounded-lg border px-3 py-2 text-left transition', ctripProfileModuleCategoryFilter === category.name ? 'border-blue-300 bg-blue-50' : 'bg-white hover:bg-gray-50']\">\n                                                                <div class=\"flex items-center justify-between gap-2\">\n                                                                    <span class=\"text-sm font-semibold text-gray-900\">{{ category.name }}</span>\n                                                                    <span class=\"rounded-full bg-gray-100 px-2 py-0.5 text-xs text-gray-600\">{{ category.count }}项</span>\n                                                                </div>\n                                                            </button>\n                                                        </div>\n                                                    </div>\n                                                    <div class=\"grid grid-cols-1 lg:grid-cols-12 gap-4\">\n                                                        <div class=\"rounded-lg border bg-gray-50 p-3 lg:col-span-4 xl:col-span-3\">\n                                                            <div class=\"text-sm font-medium text-gray-900\">{{ ctripProfileModuleForm.id ? '编辑模块' : '新增模块' }}</div>\n                                                            <div class=\"mt-3 space-y-2\">\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    模块名称\n                                                                    <input v-model.trim=\"ctripProfileModuleForm.label\" type=\"text\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\" placeholder=\"如 经营报告-概要-日报\">\n                                                                </label>\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    模块编码\n                                                                    <input v-model.trim=\"ctripProfileModuleForm.id\" type=\"text\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\" placeholder=\"如 business_overview\">\n                                                                </label>\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    对应网页URL\n                                                                    <input v-model.trim=\"ctripProfileModuleForm.page_url\" type=\"url\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\" placeholder=\"https://ebooking.ctrip.com/...\">\n                                                                </label>\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    一级指标\n                                                                    <select v-model=\"ctripProfileModuleForm.primary_category\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\">\n                                                                        <option value=\"\">请选择一级指标</option>\n                                                                        <option v-for=\"category in ctripProfilePrimaryCategoryOptions\" :key=\"category\" :value=\"category\">{{ category }}</option>\n                                                                    </select>\n                                                                </label>\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    排序\n                                                                    <input v-model.number=\"ctripProfileModuleForm.sort_order\" type=\"number\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\">\n                                                                </label>\n                                                                <label class=\"flex items-center gap-2 rounded-lg border bg-white px-3 py-1.5 text-sm text-gray-700\">\n                                                                    <input v-model=\"ctripProfileModuleForm.enabled\" type=\"checkbox\" class=\"rounded border-gray-300 text-blue-600\">\n                                                                    启用模块\n                                                                </label>\n                                                                <label class=\"block text-xs font-medium text-gray-600\">\n                                                                    备注\n                                                                    <textarea v-model.trim=\"ctripProfileModuleForm.description\" rows=\"2\" class=\"mt-1 w-full px-3 py-1.5 border rounded-lg text-sm font-normal text-gray-900 bg-white\" placeholder=\"可记录页面范围、授权要求或口径说明\"></textarea>\n                                                                </label>\n                                                                <div class=\"flex justify-end gap-2 pt-1\">\n                                                                    <button type=\"button\" @click=\"resetCtripProfileModuleForm\" class=\"px-3 py-2 border rounded-lg text-sm hover:bg-white\">清空</button>\n                                                                    <button type=\"button\" @click=\"saveCtripProfileModule\" :disabled=\"ctripProfileModuleSaving\" class=\"px-4 py-2 bg-blue-600 text-white rounded-lg text-sm hover:bg-blue-700 disabled:bg-gray-400\">\n                                                                        {{ ctripProfileModuleSaving ? '保存中...' : '保存模块' }}\n                                                                    </button>\n                                                                </div>\n                                                            </div>\n                                                        </div>\n                                                        <div class=\"rounded-lg border overflow-hidden lg:col-span-8 xl:col-span-9\">\n                                                            <table class=\"w-full table-fixed text-sm\">\n                                                                <thead class=\"bg-gray-50 text-xs text-gray-500\">\n                                                                    <tr>\n                                                                        <th class=\"w-[30%] px-3 py-2 text-left font-medium\">模块</th>\n                                                                        <th class=\"w-[40%] px-3 py-2 text-left font-medium\">对应网页</th>\n                                                                        <th class=\"w-[70px] px-3 py-2 text-left font-medium\">字段</th>\n                                                                        <th class=\"w-[72px] px-3 py-2 text-left font-medium\">状态</th>\n                                                                        <th class=\"w-[92px] px-3 py-2 text-right font-medium\">操作</th>\n                                                                    </tr>\n                                                                </thead>\n                                                                <tbody class=\"divide-y\">\n                                                                    <tr v-for=\"module in ctripProfileModuleRows\" :key=\"module.id\" class=\"hover:bg-gray-50\">\n                                                                        <td class=\"px-3 py-2 align-top\">\n                                                                            <a v-if=\"ctripProfileModulePageUrl(module)\" :href=\"ctripProfileModulePageUrl(module)\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"font-medium text-blue-700 hover:underline text-left\" title=\"外部打开对应网页\">\n                                                                                {{ module.label }}\n                                                                            </a>\n                                                                            <div v-else class=\"font-medium text-gray-900\">{{ module.label }}</div>\n                                                                            <div class=\"font-mono text-xs text-gray-500\">{{ module.id }}</div>\n                                                                            <div v-if=\"module.primary_category\" class=\"mt-1 inline-flex rounded border border-blue-100 bg-blue-50 px-2 py-0.5 text-xs text-blue-700\">{{ module.primary_category }}</div>\n                                                                            <div v-if=\"module.description\" class=\"mt-1 text-xs text-gray-500 line-clamp-2\">{{ module.description }}</div>\n                                                                        </td>\n                                                                        <td class=\"px-3 py-2 align-top\">\n                                                                            <div v-if=\"ctripProfileModulePageUrl(module)\" class=\"min-w-0\">\n                                                                                <a :href=\"ctripProfileModulePageUrl(module)\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"inline-flex items-center gap-1 rounded border border-blue-100 bg-blue-50 px-2 py-0.5 text-xs text-blue-700 hover:bg-blue-100\" title=\"外部打开对应网页\">\n                                                                                    <i class=\"fas fa-external-link-alt text-[10px]\"></i>外部打开\n                                                                                </a>\n                                                                                <div class=\"mt-1 truncate font-mono text-xs text-gray-500\" :title=\"ctripProfileModulePageUrl(module)\">\n                                                                                    {{ ctripProfileModulePageDisplay(module) }}\n                                                                                </div>\n                                                                            </div>\n                                                                            <span v-else class=\"text-xs text-gray-400\">未配置</span>\n                                                                        </td>\n                                                                        <td class=\"px-3 py-2 align-top text-gray-700 whitespace-nowrap\">\n                                                                            {{ module.enabled_field_count || 0 }} / {{ module.field_count || 0 }}\n                                                                        </td>\n                                                                        <td class=\"px-3 py-2 align-top\">\n                                                                            <span :class=\"['inline-flex whitespace-nowrap rounded border px-2 py-0.5 text-xs', module.enabled ? 'border-emerald-100 bg-emerald-50 text-emerald-700' : 'border-gray-200 bg-gray-100 text-gray-500']\">\n                                                                                {{ module.enabled ? '启用' : '停用' }}\n                                                                            </span>\n                                                                        </td>\n                                                                        <td class=\"px-3 py-2 align-top text-right whitespace-nowrap\">\n                                                                            <a v-if=\"ctripProfileModulePageUrl(module)\" :href=\"ctripProfileModulePageUrl(module)\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"text-emerald-600 hover:text-emerald-700 mr-3\" title=\"外部打开对应网页\"><i class=\"fas fa-external-link-alt\"></i></a>\n                                                                            <button v-else type=\"button\" @click=\"openCtripProfileModulePage(module)\" class=\"text-gray-300 mr-3\" title=\"未配置对应网页\"><i class=\"fas fa-external-link-alt\"></i></button>\n                                                                            <button type=\"button\" @click=\"editCtripProfileModule(module)\" class=\"text-blue-600 hover:text-blue-700 mr-3\" title=\"编辑模块\"><i class=\"fas fa-edit\"></i></button>\n                                                                            <button type=\"button\" @click=\"deleteCtripProfileModule(module)\" :disabled=\"ctripProfileModuleDeletingId === module.id\" class=\"text-red-500 hover:text-red-700 disabled:text-gray-300\" title=\"删除模块\"><i :class=\"ctripProfileModuleDeletingId === module.id ? 'fas fa-spinner fa-spin' : 'fas fa-trash'\"></i></button>\n                                                                        </td>\n                                                                    </tr>\n                                                                    <tr v-if=\"ctripProfileModuleRows.length === 0\">\n                                                                        <td colspan=\"5\" class=\"px-3 py-8 text-center text-gray-500\">暂无模块配置</td>\n                                                                    </tr>\n                                                                </tbody>\n                                                            </table>\n                                                        </div>\n                                                    </div>\n                                                </div>\n                                                <div class=\"flex shrink-0 justify-end gap-2 border-t bg-white px-4 py-3\">\n                                                    <button type=\"button\" @click=\"closeCtripProfileModuleManager\" class=\"px-3 py-2 border rounded-lg text-sm hover:bg-gray-50\">关闭</button>\n                                                </div>\n                                            </div>\n                                            </div>\n                                        </div>\n                            </teleport>\n\n                                        <teleport to=\"body\">\n                                        <div v-if=\"showCtripProfileFieldForm\"\n                                            class=\"fixed inset-0 bg-slate-900/45 px-4 py-6 overflow-y-auto\"\n                                            style=\"z-index: 80;\"\n                                            data-testid=\"ctrip-profile-field-modal\">\n                                            <div class=\"flex min-h-full items-center justify-center\" @click.self=\"resetCtripProfileFieldForm\">\n                                            <div class=\"flex w-full max-w-5xl max-h-[calc(100vh-72px)] flex-col rounded-lg bg-white shadow-2xl\">\n                                                <div class=\"flex items-start justify-between gap-3 border-b px-4 py-3\">\n                                                    <div>\n                                                        <div class=\"text-base font-semibold text-gray-900\">\n                                                            {{ ctripProfileFieldForm.id ? '编辑字段配置' : '新增字段配置' }}\n                                                        </div>\n                                                        <div class=\"mt-1 text-xs text-gray-500\">\n                                                            只需要确认来源、字段含义和获取值；采集范围、字段编码、来源字段和入库规则由系统按 URL 与 JSON 路径预判。\n                                                        </div>\n                                                    </div>\n                                                    <button type=\"button\" @click=\"resetCtripProfileFieldForm\"\n                                                        class=\"h-8 w-8 shrink-0 rounded-lg border text-gray-500 hover:bg-gray-50\"\n                                                        title=\"关闭\">\n                                                        <i class=\"fas fa-times\"></i>\n                                                    </button>\n                                                </div>\n                                                <div class=\"min-h-0 flex-1 overflow-y-auto p-4 space-y-4\">\n                                                    <div class=\"rounded-lg border bg-slate-50 p-3\">\n                                                        <div class=\"mb-3 flex flex-wrap items-center justify-between gap-2\">\n                                                            <div>\n                                                                <div class=\"text-sm font-semibold text-gray-900\">来源与业务含义</div>\n                                                                <div class=\"text-xs text-gray-500\">优先填页面、JSON 路径和字段含义；接口 URL 可由获取值或抓包补充。</div>\n                                                            </div>\n                                                            <button type=\"button\" @click=\"applyCtripProfileFieldSmartDefaults\"\n                                                                class=\"rounded-lg border bg-white px-3 py-1.5 text-xs text-gray-700 hover:bg-gray-50\">\n                                                                <i class=\"fas fa-wand-magic-sparkles mr-1\"></i>自动整理\n                                                            </button>\n                                                        </div>\n                                                        <div class=\"grid grid-cols-1 md:grid-cols-2 gap-3\">\n                                                            <label class=\"block text-xs font-medium text-gray-600\">\n                                                                网页URL\n                                                                <input v-model.trim=\"ctripProfileFieldForm.page_url\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"携程后台页面地址\">\n                                                            </label>\n                                                            <label class=\"block text-xs font-medium text-gray-600\">\n                                                                接口URL\n                                                                <input v-model.trim=\"ctripProfileFieldForm.request_url\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"真实业务接口地址，可选\">\n                                                            </label>\n                                                            <label class=\"block text-xs font-medium text-gray-600\">\n                                                                JSON路径 / 字段\n                                                                <textarea v-model.trim=\"ctripProfileFieldForm.json_path\" rows=\"2\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"如 data.amount 或 amount\"></textarea>\n                                                            </label>\n                                                            <label class=\"block text-xs font-medium text-gray-600\">\n                                                                字段含义\n                                                                <input v-model.trim=\"ctripProfileFieldForm.value_meaning\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"如 离店销售额、实时访客量\">\n                                                            </label>\n                                                        </div>\n                                                    </div>\n\n                                                    <div class=\"rounded-lg border bg-white p-3\">\n                                                        <div class=\"mb-2 flex flex-wrap items-center justify-between gap-2\">\n                                                            <div class=\"text-sm font-semibold text-gray-900\">系统判断</div>\n                                                            <label class=\"inline-flex items-center gap-2 text-xs text-gray-600\">\n                                                                <input v-model=\"ctripProfileFieldForm.enabled\" type=\"checkbox\" class=\"rounded\">\n                                                                启用采集\n                                                            </label>\n                                                        </div>\n                                                        <div class=\"grid grid-cols-1 md:grid-cols-5 gap-2 text-xs\">\n                                                            <div class=\"rounded border bg-gray-50 px-3 py-2\">\n                                                                <div class=\"text-gray-500\">采集范围</div>\n                                                                <div class=\"mt-1 font-medium text-gray-900\">{{ ctripProfileFieldInferredSectionText }}</div>\n                                                            </div>\n                                                            <div class=\"rounded border bg-gray-50 px-3 py-2\">\n                                                                <div class=\"text-gray-500\">来源接口</div>\n                                                                <div class=\"mt-1 font-mono text-gray-900 truncate\" :title=\"ctripProfileFieldInferredEndpoint\">{{ ctripProfileFieldInferredEndpoint || '-' }}</div>\n                                                            </div>\n                                                            <div class=\"rounded border bg-gray-50 px-3 py-2\">\n                                                                <div class=\"text-gray-500\">来源字段</div>\n                                                                <div class=\"mt-1 font-mono text-gray-900 truncate\" :title=\"ctripProfileFieldInferredSourceKey\">{{ ctripProfileFieldInferredSourceKey || '-' }}</div>\n                                                            </div>\n                                                            <div class=\"rounded border bg-gray-50 px-3 py-2\">\n                                                                <div class=\"text-gray-500\">字段编码</div>\n                                                                <div class=\"mt-1 font-mono text-gray-900 truncate\" :title=\"ctripProfileFieldInferredFieldKey\">{{ ctripProfileFieldInferredFieldKey || '-' }}</div>\n                                                            </div>\n                                                            <div class=\"rounded border bg-gray-50 px-3 py-2\">\n                                                                <div class=\"text-gray-500\">入库规则</div>\n                                                                <div class=\"mt-1 font-mono text-gray-900 truncate\" :title=\"ctripProfileFieldInferredStorageField\">{{ ctripProfileFieldInferredStorageField || '-' }}</div>\n                                                            </div>\n                                                        </div>\n                                                    </div>\n\n                                                    <details class=\"rounded-lg border bg-white\">\n                                                    <summary class=\"cursor-pointer px-3 py-2 text-sm font-medium text-gray-700\">高级配置</summary>\n                                                    <div class=\"grid grid-cols-1 md:grid-cols-4 gap-3 border-t p-3\">\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            采集范围\n                                                            <select v-model=\"ctripProfileFieldForm.section\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900 bg-white\">\n                                                                <option v-for=\"option in ctripProfileFieldSectionOptions\" :key=\"option.value\" :value=\"option.value\">{{ option.label }}</option>\n                                                            </select>\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            页面位置\n                                                            <input v-model.trim=\"ctripProfileFieldForm.page_location\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"菜单路径或页面卡片位置\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            来源字段名\n                                                            <input v-model.trim=\"ctripProfileFieldForm.target_field\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"原始接口字段名\">\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            字段编码\n                                                            <input v-model.trim=\"ctripProfileFieldForm.field_key\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"如 order_amount\">\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            字段名称\n                                                            <input v-model.trim=\"ctripProfileFieldForm.field_name\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"中文名称\">\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            配置状态\n                                                            <select v-model=\"ctripProfileFieldForm.status\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900 bg-white\">\n                                                                <option value=\"confirmed\">已确认</option>\n                                                                <option value=\"needs_section\">需采集范围</option>\n                                                                <option value=\"needs_parser\">待补解析</option>\n                                                                <option value=\"not_captured\">未采集</option>\n                                                                <option value=\"pending\">待确认</option>\n                                                                <option value=\"paused\">停用</option>\n                                                            </select>\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            排序\n                                                            <input v-model.number=\"ctripProfileFieldForm.sort_order\" type=\"number\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"数字越小越靠前\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            来源接口\n                                                            <input v-model.trim=\"ctripProfileFieldForm.source_interface\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"接口或采集模块标识\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            来源字段\n                                                            <input v-model.trim=\"ctripProfileFieldForm.source_keys\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"可多个，用逗号分隔\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            数据归属规则\n                                                            <input v-model.trim=\"ctripProfileFieldForm.ownership_rule\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"说明本店、竞品或平台口径\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            入库字段\n                                                            <input v-model.trim=\"ctripProfileFieldForm.storage_field\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"如 online_daily_data.amount\">\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            值类型\n                                                            <input v-model.trim=\"ctripProfileFieldForm.value_type\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"integer / decimal / rank\">\n                                                        </label>\n                                                        <label class=\"block text-xs font-medium text-gray-600\">\n                                                            单位\n                                                            <input v-model.trim=\"ctripProfileFieldForm.unit\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"元 / 单 / 名\">\n                                                        </label>\n                                                        <label class=\"md:col-span-2 block text-xs font-medium text-gray-600\">\n                                                            转换规则\n                                                            <input v-model.trim=\"ctripProfileFieldForm.transform_rule\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"直接取值、比例换算或过滤规则\">\n                                                        </label>\n                                                        <label class=\"md:col-span-4 block text-xs font-medium text-gray-600\">\n                                                            备注\n                                                            <input v-model.trim=\"ctripProfileFieldForm.notes\" type=\"text\" class=\"mt-1 w-full px-3 py-2 border rounded-lg text-sm font-normal text-gray-900\" placeholder=\"补充口径、风险或待确认事项\">\n                                                        </label>\n                                                    </div>\n                                                </details>\n\n                                                <div v-if=\"ctripProfileFieldForm.id\" class=\"rounded-lg border bg-white p-3\">\n                                                <div class=\"flex items-center justify-between gap-3 mb-2\">\n                                                    <div class=\"text-sm font-medium text-gray-800\">当前字段获取值</div>\n                                                    <button type=\"button\" @click=\"openCtripProfileFieldSamplePanel(editingCtripProfileField)\"\n                                                        class=\"text-xs text-blue-600 hover:text-blue-700\">\n                                                        查看历史获取值\n                                                    </button>\n                                                </div>\n                                                <div v-if=\"ctripProfileFieldForm.verified_sample_value\" class=\"mb-2 rounded border border-emerald-100 bg-emerald-50 px-2 py-1.5 text-xs text-emerald-800\">\n                                                    已选正确获取值：<span class=\"font-mono\">{{ ctripProfileFieldForm.verified_sample_value }}</span>\n                                                    <span v-if=\"ctripProfileFieldForm.verified_sample_source_path\"> · {{ ctripProfileFieldForm.verified_sample_source_path }}</span>\n                                                </div>\n                                                <div v-if=\"editingCtripProfileFieldSamples.length\" class=\"grid grid-cols-1 md:grid-cols-2 gap-2\">\n                                                    <div v-for=\"(sample, index) in editingCtripProfileFieldSamples.slice(0, 4)\" :key=\"`editing-sample-${index}`\"\n                                                        :class=\"['rounded border px-2 py-1.5', isCtripProfileCorrectSampleSelected(sample, ctripProfileFieldForm) ? 'border-emerald-300 bg-emerald-50' : 'bg-white']\">\n                                                        <div class=\"flex items-start justify-between gap-2\">\n                                                            <div class=\"min-w-0\">\n                                                                <div class=\"font-mono text-gray-900 break-words\">{{ ctripProfileFieldSampleValueText(sample) }}</div>\n                                                                <div class=\"text-xs text-gray-500 mt-1\">{{ ctripProfileFieldSampleMetaText(sample) || '无获取值上下文' }}</div>\n                                                            </div>\n                                                            <button type=\"button\" @click=\"selectCtripProfileCorrectSample(editingCtripProfileField, sample)\"\n                                                                :class=\"['shrink-0 rounded border px-2 py-1 text-xs', isCtripProfileCorrectSampleSelected(sample, ctripProfileFieldForm) ? 'border-emerald-200 bg-emerald-100 text-emerald-700' : 'border-blue-100 bg-blue-50 text-blue-700 hover:bg-blue-100']\">\n                                                                {{ isCtripProfileCorrectSampleSelected(sample, ctripProfileFieldForm) ? '已选择' : '选为正确数据' }}\n                                                            </button>\n                                                        </div>\n                                                    </div>\n                                                </div>\n                                                <div v-else class=\"text-sm text-gray-400\">{{ ctripProfileFieldSampleLoading ? '字段获取值加载中...' : '这个字段当前没有获取值，需检查来源接口、来源字段或采集范围。' }}</div>\n                                                </div>\n                                            </div>\n\n                                            <div class=\"flex shrink-0 justify-end gap-2 border-t bg-white px-4 py-3\">\n                                                <button type=\"button\" @click=\"resetCtripProfileFieldForm\" class=\"px-3 py-2 border rounded-lg text-sm hover:bg-gray-50\">取消</button>\n                                                <button type=\"button\" @click=\"saveCtripProfileField\" :disabled=\"ctripProfileFieldSaving\" class=\"px-4 py-2 bg-blue-600 text-white rounded-lg text-sm hover:bg-blue-700 disabled:bg-gray-400\">\n                                                    {{ ctripProfileFieldSaving ? '保存中...' : '保存字段' }}\n                                                </button>\n                                            </div>\n                                        </div>\n                                    </div>\n                                </div>\n                            </teleport>\n\n                                        <div v-if=\"selectedCtripProfileSampleField\" ref=\"ctripProfileSamplePanel\" class=\"p-4 border-b bg-blue-50/50\">\n                                            <div class=\"rounded-lg border bg-white overflow-hidden\">\n                                                <div class=\"px-4 py-3 border-b flex flex-col md:flex-row md:items-center md:justify-between gap-2\">\n                                                    <div>\n                                                        <div class=\"text-sm font-semibold text-gray-900\">\n                                                            获取值明细：{{ selectedCtripProfileSampleField.field_name || '-' }}\n                                                        </div>\n                                                        <div class=\"text-xs text-gray-500 font-mono mt-1\">{{ selectedCtripProfileSampleField.field_key || '-' }}</div>\n                                                        <div class=\"text-xs text-gray-500 mt-1\">\n                                                            历史获取值 {{ ctripProfileFieldSampleLoading ? '加载中...' : (ctripProfileFieldLatestSampleTime(selectedCtripProfileSampleField) || '未获取到值') }}；仅显示最近一次采集批次\n                                                        </div>\n                                                    </div>\n                                                    <div class=\"flex items-center gap-2\">\n                                                        <button type=\"button\" @click=\"editCtripProfileField(selectedCtripProfileSampleField)\"\n                                                            class=\"px-3 py-1.5 text-xs border rounded-lg hover:bg-gray-50\">\n                                                            编辑字段\n                                                        </button>\n                                                        <button type=\"button\" @click=\"closeCtripProfileFieldSamplePanel\"\n                                                            class=\"px-3 py-1.5 text-xs border rounded-lg hover:bg-gray-50\">\n                                                            关闭\n                                                        </button>\n                                                    </div>\n                                                </div>\n                                                <div v-if=\"selectedCtripProfileFieldSamples.length\" class=\"overflow-x-auto\">\n                                                    <table class=\"w-full text-xs\">\n                                                        <thead class=\"bg-gray-50 text-gray-500\">\n                                                            <tr>\n                                                                <th class=\"px-3 py-2 text-left font-medium w-[150px]\">获取值</th>\n                                                                <th class=\"px-3 py-2 text-left font-medium w-[120px]\">日期/门店</th>\n                                                                <th class=\"px-3 py-2 text-left font-medium w-[180px]\">来源接口</th>\n                                                                <th class=\"px-3 py-2 text-left font-medium w-[160px]\">来源字段</th>\n                                                                <th class=\"px-3 py-2 text-left font-medium\">来源路径</th>\n                                                                <th class=\"px-3 py-2 text-right font-medium w-[120px]\">确认</th>\n                                                            </tr>\n                                                        </thead>\n                                                        <tbody class=\"divide-y divide-gray-100\">\n                                                            <tr v-for=\"(sample, index) in selectedCtripProfileFieldSamples\" :key=\"`profile-sample-detail-${index}`\">\n                                                                <td class=\"px-3 py-2 align-top\">\n                                                                    <div class=\"font-mono text-gray-900 whitespace-pre-wrap break-words\">{{ ctripProfileFieldSampleValueText(sample) || '-' }}</div>\n                                                                    <div v-if=\"sample.captured_at\" class=\"text-gray-400 mt-1\">{{ sample.captured_at }}</div>\n                                                                </td>\n                                                                <td class=\"px-3 py-2 align-top text-gray-600\">\n                                                                    <div>{{ sample.data_date || '-' }}</div>\n                                                                    <div class=\"text-gray-400 mt-1 truncate\" :title=\"sample.hotel_name\">{{ sample.hotel_name || '-' }}</div>\n                                                                </td>\n                                                                <td class=\"px-3 py-2 align-top text-gray-600\">\n                                                                    <div class=\"truncate\" :title=\"sample.endpoint_id || sample.capture_section\">{{ sample.endpoint_id || sample.capture_section || '-' }}</div>\n                                                                    <div v-if=\"sample.capture_status\" class=\"text-gray-400 mt-1\">{{ sample.capture_status }}</div>\n                                                                </td>\n                                                                <td class=\"px-3 py-2 align-top text-gray-600 font-mono break-words\">{{ sample.source_key || '-' }}</td>\n                                                                <td class=\"px-3 py-2 align-top text-gray-600 font-mono break-words\">{{ sample.source_path || '-' }}</td>\n                                                                <td class=\"px-3 py-2 align-top text-right\">\n                                                                    <button type=\"button\" @click=\"selectCtripProfileCorrectSample(selectedCtripProfileSampleField, sample)\"\n                                                                        class=\"rounded border border-blue-100 bg-blue-50 px-2 py-1 text-xs text-blue-700 hover:bg-blue-100\">\n                                                                        选为正确数据\n                                                                    </button>\n                                                                </td>\n                                                            </tr>\n                                                        </tbody>\n                                                    </table>\n                                                </div>\n                                                <div v-else class=\"p-4 text-sm text-gray-500\">\n                                                    {{ ctripProfileFieldSampleLoading ? '最近批次获取值加载中...' : '当前字段没有历史获取值。优先检查来源接口、来源字段、采集范围，或先执行一次自动获取后再回到这里确认。' }}\n                                                </div>\n                                            </div>\n                                        </div>\n\n                                        <div v-if=\"ctripProfileFieldLoading\" class=\"p-8 text-center text-gray-500\">字段加载中...</div>\n                                        <div v-else class=\"overflow-x-auto\">\n                                            <table class=\"w-full table-fixed text-sm\" style=\"min-width: 1460px;\">\n                                                <colgroup>\n                                                    <col style=\"width: 220px;\">\n                                                    <col style=\"width: 76px;\">\n                                                    <col style=\"width: 330px;\">\n                                                    <col style=\"width: 88px;\">\n                                                    <col style=\"width: 96px;\">\n                                                    <col style=\"width: 150px;\">\n                                                    <col style=\"width: 440px;\">\n                                                    <col style=\"width: 118px;\">\n                                                </colgroup>\n                                                <thead class=\"bg-gray-50 text-gray-600\">\n                                                    <tr>\n                                                        <th class=\"w-[220px] px-4 py-3 text-left font-medium\">字段配置</th>\n                                                        <th class=\"w-[76px] px-4 py-3 text-left font-medium\">采集范围</th>\n                                                        <th class=\"w-[330px] px-4 py-3 text-left font-medium\">获取值 / 人工核验</th>\n                                                        <th class=\"w-[88px] px-4 py-3 text-left font-medium\">配置状态</th>\n                                                        <th class=\"w-[96px] px-4 py-3 text-left font-medium\">开关</th>\n                                                        <th class=\"w-[150px] px-4 py-3 text-left font-medium\">最近采集/更新</th>\n                                                        <th class=\"w-[440px] px-4 py-3 text-left font-medium\">来源与入库规则</th>\n                                                        <th class=\"w-[118px] px-4 py-3 text-right font-medium\">配置操作</th>\n                                                    </tr>\n                                                </thead>\n                                                <tbody class=\"divide-y divide-gray-200\">\n                                                    <tr v-for=\"field in filteredCtripProfileFields\" :key=\"field.id\" class=\"hover:bg-gray-50\">\n                                                        <td class=\"px-4 py-3 align-top\">\n                                                            <div class=\"font-medium text-gray-900 truncate\" :title=\"field.field_name\">{{ field.field_name || '-' }}</div>\n                                                            <div class=\"text-xs text-gray-500 font-mono truncate\" :title=\"field.field_key\">{{ field.field_key || '-' }}</div>\n                                                            <div v-if=\"field.value_meaning\" class=\"text-xs text-gray-500 truncate mt-1\" :title=\"field.value_meaning\">{{ field.value_meaning }}</div>\n                                                            <div class=\"mt-2 border-t border-gray-100 pt-2 text-xs\">\n                                                                <div v-if=\"ctripProfileFieldPreviewSampleItems(field).length\" class=\"space-y-1\">\n                                                                    <div v-for=\"(sample, index) in ctripProfileFieldPreviewSampleItems(field)\" :key=\"`${field.id}-field-sample-${index}`\">\n                                                                        <div class=\"text-[11px] text-gray-500\">{{ ctripProfileFieldDisplaySampleLabel(field) }}</div>\n                                                                        <div class=\"font-mono text-blue-700 break-words leading-5\" :title=\"ctripProfileFieldSampleValueText(sample)\">\n                                                                            {{ ctripProfileFieldSampleValueText(sample) }}\n                                                                        </div>\n                                                                    </div>\n                                                                </div>\n                                                                <div v-else class=\"text-gray-400\">\n                                                                    获取值：{{ ctripProfileFieldSampleLoading ? '获取值加载中...' : (ctripProfileFieldSamplesLoaded ? (field.latest_sample_note || '未获取到值') : '获取值未加载') }}\n                                                                </div>\n                                                            </div>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top text-gray-700\">{{ ctripProfileCaptureSectionText(field.section) }}</td>\n                                                        <td class=\"px-4 py-3 align-top\">\n                                                            <div v-if=\"ctripProfileFieldPreviewSampleItems(field).length\" class=\"space-y-1\">\n                                                                <div v-for=\"(sample, index) in ctripProfileFieldPreviewSampleItems(field)\" :key=\"`${field.id}-sample-${index}`\" class=\"rounded border bg-white px-2 py-1.5\">\n                                                                    <div class=\"flex items-start justify-between gap-2\">\n                                                                        <div class=\"min-w-0\">\n                                                                            <div class=\"text-[11px] text-gray-500\">{{ ctripProfileFieldDisplaySampleLabel(field) }}</div>\n                                                                            <div class=\"font-mono text-gray-900 break-words leading-5\" :title=\"ctripProfileFieldSampleValueText(sample)\">\n                                                                                {{ ctripProfileFieldSampleValueText(sample) }}\n                                                                            </div>\n                                                                            <div v-if=\"ctripProfileFieldSampleBriefMetaText(sample)\" class=\"text-xs text-gray-400 mt-1 truncate\" :title=\"ctripProfileFieldSampleMetaText(sample)\">\n                                                                                {{ ctripProfileFieldSampleBriefMetaText(sample) }}\n                                                                            </div>\n                                                                        </div>\n                                                                        <button v-if=\"ctripProfileFieldDisplaySampleCount(field) > 1\" type=\"button\"\n                                                                            @click=\"openCtripProfileFieldSamplePanel(field)\"\n                                                                            class=\"shrink-0 rounded border border-blue-100 bg-blue-50 px-2 py-0.5 text-xs text-blue-700 hover:bg-blue-100\"\n                                                                            title=\"查看全部获取值\">\n                                                                            {{ ctripProfileFieldDisplaySampleCount(field) }}条\n                                                                        </button>\n                                                                    </div>\n                                                                </div>\n                                                            </div>\n                                                            <div v-else class=\"rounded border border-dashed border-gray-200 bg-gray-50 px-2 py-1.5 text-xs\">\n                                                                <div class=\"text-gray-500\">获取值</div>\n                                                                <div class=\"mt-0.5 text-gray-400\">\n                                                                    {{ ctripProfileFieldSampleLoading ? '获取值加载中...' : (ctripProfileFieldSamplesLoaded ? (field.latest_sample_note || '未获取到值') : '获取值未加载') }}\n                                                                </div>\n                                                            </div>\n                                                            <div class=\"mt-2 flex flex-wrap items-center gap-1.5\">\n                                                                <span :class=\"['inline-flex items-center gap-1.5 rounded-full border px-2 py-1 text-xs whitespace-nowrap', ctripProfileFieldVerificationBadgeClass(field.sample_verification_status)]\">\n                                                                    <span :class=\"['h-2 w-2 rounded-full', ctripProfileFieldVerificationLightClass(field.sample_verification_status)]\"></span>\n                                                                    <span>{{ ctripProfileFieldVerificationText(field.sample_verification_status) }}</span>\n                                                                </span>\n                                                                <span v-if=\"ctripProfileFieldNeedsSecondConfirmation(field)\"\n                                                                    class=\"inline-flex items-center rounded-full border border-amber-100 bg-amber-50 px-2 py-1 text-xs text-amber-700 whitespace-nowrap\">\n                                                                    重抓后待二次确认\n                                                                </span>\n                                                                <button type=\"button\"\n                                                                    @click=\"setCtripProfileFieldVerification(field, 'matched')\"\n                                                                    :disabled=\"ctripProfileFieldVerifyingId === field.id\"\n                                                                    :class=\"[\n                                                                        'rounded border px-2 py-1 text-xs disabled:opacity-60',\n                                                                        normalizeCtripProfileFieldVerificationStatus(field.sample_verification_status) === 'matched'\n                                                                            ? 'border-emerald-200 bg-emerald-50 text-emerald-700'\n                                                                            : 'border-gray-200 text-gray-600 hover:bg-emerald-50 hover:text-emerald-700'\n                                                                    ]\">\n                                                                    相符\n                                                                </button>\n                                                                <button type=\"button\"\n                                                                    @click=\"setCtripProfileFieldVerification(field, 'mismatched')\"\n                                                                    :disabled=\"ctripProfileFieldVerifyingId === field.id\"\n                                                                    :class=\"[\n                                                                        'rounded border px-2 py-1 text-xs disabled:opacity-60',\n                                                                        normalizeCtripProfileFieldVerificationStatus(field.sample_verification_status) === 'mismatched'\n                                                                            ? 'border-red-200 bg-red-50 text-red-700'\n                                                                            : 'border-gray-200 text-gray-600 hover:bg-red-50 hover:text-red-700'\n                                                                    ]\">\n                                                                    不符\n                                                                </button>\n                                                            </div>\n                                                            <div v-if=\"field.sample_verified_at\" class=\"mt-1 text-[11px] text-gray-400 truncate\" :title=\"field.sample_verified_at\">\n                                                                {{ field.sample_verified_at }}\n                                                            </div>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top\">\n                                                            <span :title=\"ctripProfileFieldStatusDetailText(field.status)\" :class=\"['px-2 py-1 rounded-full border text-xs whitespace-nowrap', ctripProfileFieldStatusClass(field.status)]\">{{ ctripProfileFieldStatusText(field.status) }}</span>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top\">\n                                                            <button type=\"button\"\n                                                                @click=\"toggleCtripProfileFieldEnabled(field)\"\n                                                                :disabled=\"ctripProfileFieldTogglingId === field.id\"\n                                                                :class=\"['px-2 py-1 rounded-full text-xs whitespace-nowrap border disabled:opacity-60', field.enabled ? 'border-emerald-100 bg-emerald-50 text-emerald-700 hover:bg-emerald-100' : 'border-gray-200 bg-gray-100 text-gray-500 hover:bg-gray-200']\">\n                                                                {{ ctripProfileFieldTogglingId === field.id ? '保存中' : (field.enabled ? '启用' : '停用') }}\n                                                            </button>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top whitespace-nowrap\">\n                                                            <div v-if=\"ctripProfileFieldLatestSampleTime(field)\" class=\"text-gray-700\">{{ ctripProfileFieldLatestSampleTime(field) }}</div>\n                                                            <div v-else class=\"text-gray-400\">{{ ctripProfileFieldSampleLoading ? '获取值加载中...' : (ctripProfileFieldSamplesLoaded ? '未获取到值' : '获取值未加载') }}</div>\n                                                            <div class=\"text-xs text-gray-400 mt-1\">配置 {{ field.update_time || '-' }}</div>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top\">\n                                                            <div v-if=\"field.page_location || field.target_field || field.target_value || field.value_meaning\" class=\"mb-1 space-y-0.5\">\n                                                                <div v-if=\"field.page_location\" class=\"text-xs text-gray-500 truncate\" :title=\"field.page_location\">位置 {{ field.page_location }}</div>\n                                                                <div v-if=\"field.target_value\" class=\"text-xs text-gray-500 truncate\" :title=\"field.target_value\">要取 {{ field.target_value }}</div>\n                                                                <div v-else-if=\"field.target_field\" class=\"text-xs text-gray-500 truncate\" :title=\"field.target_field\">要取 {{ field.target_field }}</div>\n                                                                <div v-if=\"field.value_meaning\" class=\"text-xs text-gray-500 truncate\" :title=\"field.value_meaning\">含义 {{ field.value_meaning }}</div>\n                                                            </div>\n                                                            <div class=\"text-gray-900 truncate\" :title=\"field.source_interface\">{{ field.source_interface || '-' }}</div>\n                                                            <div class=\"text-xs text-gray-500 truncate\" :title=\"field.source_keys\">{{ field.source_keys || '-' }}</div>\n                                                            <div v-if=\"field.request_url || field.page_url\" class=\"mt-1 space-y-0.5\">\n                                                                <div v-if=\"field.page_url\" class=\"text-xs text-gray-500 truncate\" :title=\"field.page_url\">页面 {{ field.page_url }}</div>\n                                                                <div v-if=\"field.request_url\" class=\"text-xs text-gray-500 truncate\" :title=\"field.request_url\">接口 {{ field.request_url }}</div>\n                                                            </div>\n                                                            <div v-if=\"field.json_path || field.ownership_rule || field.storage_field\" class=\"mt-1 space-y-0.5\">\n                                                                <div v-if=\"field.json_path\" class=\"text-xs text-gray-500 truncate\" :title=\"field.json_path\">JSON {{ field.json_path }}</div>\n                                                                <div v-if=\"field.ownership_rule\" class=\"text-xs text-gray-500 truncate\" :title=\"field.ownership_rule\">归属 {{ field.ownership_rule }}</div>\n                                                                <div v-if=\"field.storage_field\" class=\"text-xs text-gray-500 truncate\" :title=\"field.storage_field\">入库 {{ field.storage_field }}</div>\n                                                            </div>\n                                                            <div v-if=\"ctripProfileFieldSampleSourceText(field)\" class=\"text-xs text-blue-600 truncate mt-1\" :title=\"ctripProfileFieldSampleSourceText(field)\">\n                                                                {{ ctripProfileFieldSampleSourceText(field) }}\n                                                            </div>\n                                                        </td>\n                                                        <td class=\"px-4 py-3 align-top text-right whitespace-nowrap\">\n                                                            <button type=\"button\" @click=\"openCtripProfileFieldSamplePanel(field)\" class=\"text-slate-600 hover:text-slate-800 mr-3\" title=\"查看历史获取值\"><i class=\"fas fa-eye\"></i></button>\n                                                            <button type=\"button\" @click=\"editCtripProfileField(field)\" class=\"text-blue-600 hover:text-blue-700 mr-3\"><i class=\"fas fa-edit\"></i></button>\n                                                            <button type=\"button\" @click=\"deleteCtripProfileField(field)\" class=\"text-red-500 hover:text-red-700\"><i class=\"fas fa-trash\"></i></button>\n                                                        </td>\n                                                    </tr>\n                                                    <tr v-if=\"filteredCtripProfileFields.length === 0\">\n                                                        <td colspan=\"8\" class=\"px-4 py-8 text-center text-gray-500\">暂无匹配字段配置</td>\n                                                    </tr>\n                                                </tbody>\n                                            </table>\n                                        </div>\n                                    </div>\n                                </div>"
    };

    window.SUXI_ONLINE_DATA_COMPONENTS = components;
})();
